# The else block runs if the loop completed WITHOUT a break
def find_prime(numbers):
    for n in numbers:
        for divisor in range(2, n):
            if n % divisor == 0:
                break           # Not prime
        else:
            print(f"{n} is prime!")   # Only runs if inner loop didn't break

find_prime([2, 3, 4, 5, 6, 7])

# Practical use: search with break
needle = "admin"
users  = ["alice", "bob", "charlie"]

for user in users:
    if user == needle:
        print("Found admin!")
        break
else:
    print("Admin not found")    # Runs because we never broke out

# Build a dict from scratch
squares_dict = {x: x**2 for x in range(5)}
print(squares_dict)   # {0: 0, 1: 1, 2: 4, 3: 9, 4: 16}

# Flip keys and values
original = {"a": 1, "b": 2, "c": 3}
flipped  = {v: k for k, v in original.items()}
print(flipped)   # {1: 'a', 2: 'b', 3: 'c'}

# Filter items while building
prices = {"apple": 50, "banana": 20, "mango": 80, "grape": 30}
expensive = {k: v for k, v in prices.items() if v > 25}
print(expensive)   # {'apple': 50, 'mango': 80, 'grape': 30}

# Normalize keys (real world: cleaning API responses)
raw = {"  Name  ": "Alice", "AGE": 30, "CITY ": "Hyderabad"}
clean = {k.strip().lower(): v for k, v in raw.items()}
print(clean)   # {'name': 'Alice', 'age': 30, 'city': 'Hyderabad'}

# Unique squares
unique_remainders = {x % 5 for x in range(20)}
print(unique_remainders)   # {0, 1, 2, 3, 4}  (order may vary)

# Deduplicate while transforming
words = ["Hello", "WORLD", "hello", "Python", "python"]
